mapper.select:
SELECT 
FROM `order`
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY create_time DESC

SELECT o.id, o.order_no, o.status, o.coupon_name, c.images as coupon_image, o.total_quantity, o.used_quantity, o.total_amount, o.create_time FROM `order` o LEFT JOIN coupon c ON o.coupon_id = c.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.id, o.order_no, o.user_id, o.coupon_id, o.coupon_name, o.coupon_price,
       o.total_quantity, o.paid_quantity, o.send_quantity, o.used_quantity,
       o.total_amount, o.status, o.pay_time, o.create_time, o.update_time
FROM `order` o
INNER JOIN coupon c ON o.coupon_id = c.id
WHERE c.merchant_id = #{merchantId}

    AND o.status = #{status}

ORDER BY o.create_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE `order`
status = #{status}, pay_time = #{payTime}, used_quantity = #{usedQuantity},
WHERE id = #{id}

UPDATE `order`
SET used_quantity = used_quantity + #{quantity}
WHERE id = #{id}
